#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=1000005;
ll n,a[N],b[N],s[N],c[N],ans=0x3f3f3f3f;
deque<int> q;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		a[i+n]=a[i];
	}
	for(int i=1;i<=n;i++)
	{
		cin>>b[i];
		b[i+n]=b[i];
	}
	for(int i=1;i<=n*2;i++)
	{
		c[i]=a[i]-s[i-1];
		s[i]=s[i-1]+b[i];
	}
	for(int i=1;i<n;i++)
	{
		while(!q.empty()&&c[q.back()]<=c[i]) q.pop_back();
		q.push_back(i);
	}
	for(int i=n;i<2*n;i++)
	{
		while(!q.empty()&&q.front()<i-n+1) q.pop_front();
		while(!q.empty()&&c[q.back()]<=c[i]) q.pop_back();
		q.push_back(i);
		ans=min(ans,c[q.front()]+s[i-n]);
	}
	cout<<ans;
	return 0;
}
